    function setLanguage(lang) { currentLang = lang === 'zh' ? 'zh' : 'en'; localStorage.setItem(langKey, currentLang); applyI18n(); restoreTab(); refreshAdminHeader(); }
    function token() { return localStorage.getItem(adminTokenKey) || ''; }
