    function clearConsole() { document.getElementById('output').textContent = tr('outputReady'); }
    async function api(path, options = {}) { const opts = { ...options, headers: { 'Content-Type': 'application/json', ...(options.headers || {}) } }; if (token()) opts.headers.Authorization = 'Bearer ' + token(); let res; try { res = await fetch(path, opts); } catch (_) { throw new Error(tr('networkUnavailable')); } let data = {}; try { data = await res.json(); } catch (_) {} if (!res.ok) { if (res.status === 401 && data.code === 'ADMIN_UNAUTHORIZED') { localStorage.removeItem(adminTokenKey); localStorage.removeItem(adminProfileKey); setAuthState(false); const msg = tr('sessionExpired'); document.getElementById('loginOutput').textContent = msg; showToast(msg, 'error'); throw new Error(msg); } throw new Error(data.message || res.statusText || tr('requestFailed')); } return data; }
    async function loadAdminStatus() { return api('/api/admin/status'); }
    function showAuthStage(stage) { const setup = stage === 'setup'; document.getElementById('setupStage').classList.toggle('hidden', !setup); document.getElementById('loginStage').classList.toggle('hidden', setup); document.getElementById('setupStageButton').className = setup ? 'btn-secondary' : 'btn-ghost'; document.getElementById('loginStageButton').className = setup ? 'btn-ghost' : 'btn-secondary'; }
    function setSetupAvailability(enabled) { document.getElementById('stageToggle').classList.toggle('hidden', !enabled); document.getElementById('setupStageButton').classList.toggle('hidden', !enabled); if (!enabled) { document.getElementById('setupStage').classList.add('hidden'); document.getElementById('loginStage').classList.remove('hidden'); document.getElementById('loginStageButton').className = 'btn-secondary'; } }
    async function refreshAuthStage() { try { const data = await loadAdminStatus(); const initialized = !!data.initialized; adminInitialized = initialized; setSetupAvailability(!initialized); document.getElementById('authStageHint').textContent = initialized ? tr('canLogin') : tr('needsSetup'); showAuthStage(initialized ? 'login' : 'setup'); return initialized; } catch (err) { adminInitialized = true; setSetupAvailability(false); setOutput(tr('loadAdminFailed', { error: err.message }), 'loginOutput'); showAuthStage('login'); return true; } }
    function refreshAdminHeader() { const profile = adminProfile(); document.getElementById('adminDisplayName').textContent = profile?.username || tr('administrator'); document.getElementById('adminDisplayMeta').textContent = profile?.email || tr('signedIn'); const emailInput = document.getElementById('adminEmailInput'); const userInput = document.getElementById('adminUsernameInput'); if (emailInput) emailInput.value = profile?.email || ''; if (userInput) userInput.value = profile?.username || ''; const on = !!token(); document.getElementById('authBadge').textContent = on ? tr('authenticated') : tr('loggedOut'); document.getElementById('authBadge').className = 'badge ' + (on ? 'ok' : 'warn'); }
