    function renderCenterStatus(data) { const registered = !!data.registered; const pending = !!data.pending_confirmation; const disabled = !!data.disabled; const detail = data.advertised_base_url ? tr('advertisedAs', { url: data.advertised_base_url }) : tr('noAdvertisedUrl'); const statusTitle = disabled ? ctr('disabled') : registered ? ctr('registeredOnline') : pending ? ctr('pending') : tr('notRegistered'); const statusHint = disabled ? ctr('disabledMetricHint') : registered ? ctr('registeredMetricHint') : pending ? ctr('pendingMetricHint') : tr('syncMissing'); document.getElementById('centerStatusHero').textContent = statusTitle; document.getElementById('centerStatusHint').textContent = statusHint; document.getElementById('centerStatusDetail').textContent = detail; document.getElementById('centerStatusDetailTab').textContent = detail; document.getElementById('centerAdvertisedURL').textContent = data.advertised_base_url || tr('notConfigured'); document.getElementById('centerAdvertisedHost').textContent = data.host || tr('na'); document.getElementById('centerAdvertisedPort').textContent = data.port ? String(data.port) : tr('na'); document.getElementById('visibilityHero').textContent = data.visibility === 'shared' ? tr('visibilityShared') : tr('visibilityPrivate'); document.getElementById('modeHero').textContent = data.enrollment_mode === 'approval' ? tr('enrollmentApproval') : data.enrollment_mode === 'manual' ? tr('enrollmentManual') : tr('enrollmentOpen'); document.getElementById('centerBaseURL').value = data.base_url || ''; document.getElementById('centerVisibility').value = data.visibility === 'shared' ? 'shared' : 'private'; document.getElementById('centerEnrollmentMode').value = data.enrollment_mode || 'open'; document.getElementById('centerConfigForm').classList.toggle('hidden', registered || pending || disabled); document.getElementById('centerRegisteredNotice').classList.toggle('hidden', !(registered || pending || disabled)); document.getElementById('centerRegisteredTitle').textContent = disabled ? ctr('disabled') : registered ? ctr('registeredOnline') : ctr('pending'); document.getElementById('centerRegisteredHint').textContent = disabled ? ctr('disabledHint') : registered ? ctr('registeredOnlineHint') : ctr('pendingHint'); }
    function renderBlockedEmails(items) { document.getElementById('blockedCountHero').textContent = String(items.length); const root = document.getElementById('blockedEmails'); if (!items.length) { root.innerHTML = '<div class="hint">' + tr('emptyBlocked') + '</div>'; return; } root.innerHTML = items.map(v => `<div class="item"><div class="item-head"><div class="item-title">${v.email}</div><span class="badge danger">${tr('addBlock')}</span></div><div class="item-meta">${v.reason || tr('noReason')}</div></div>`).join(''); }
    const STATUS_META = { approved: ['statusApproved','ok'], enrolled: ['statusEnrolled','ok'], pending: ['statusPending','warn'], active: ['active','info'] };
    function statusBadge(raw) { const m = STATUS_META[String(raw || '').trim().toLowerCase()]; return m ? { label: tr(m[0]), cls: m[1] } : { label: raw || tr('active'), cls: 'info' }; }
    function formatPlatformLabel(platform) { const value = String(platform || '').trim().toLowerCase(); if (!value) return tr('unknown'); if (value === 'windows') return 'Windows'; if (value === 'mac' || value === 'macos' || value === 'darwin') return 'macOS'; if (value === 'linux' || value === 'linxu') return 'Linux'; return value.charAt(0).toUpperCase() + value.slice(1); }
    function renderBoundUsers(items) { const root = document.getElementById('boundUsers'); if (!items.length) { root.innerHTML = '<div class="hint">' + tr('emptyBoundUsers') + '</div>'; return; } root.innerHTML = items.map(v => { const b = statusBadge(v.enrollment_status || v.status || 'active'); return `<div class="item"><div class="item-head"><div><div class="item-title">${v.email}</div><div class="item-meta mono">${v.sn || tr('na')}</div></div><span class="badge ${b.cls}">${b.label}</span></div></div>`; }).join(''); }
    function findMailPreset(provider) { return MAIL_PRESETS[provider] || MAIL_PRESETS.custom; }
    function detectMailProvider(cfg) { const host = String(cfg?.smtp_host || '').trim().toLowerCase(); const port = Number(cfg?.smtp_port || 0); const encryption = String(cfg?.smtp_encryption || '').trim().toLowerCase(); for (const [provider, preset] of Object.entries(MAIL_PRESETS)) { if (provider === 'custom') continue; if (host === preset.smtp_host && (!port || port === preset.smtp_port) && (!encryption || encryption === preset.smtp_encryption)) return provider; } return String(cfg?.provider || '').trim() || 'custom'; }
    function renderMailConfig(cfg = {}) { const provider = detectMailProvider(cfg); document.getElementById('mailProvider').value = MAIL_PRESETS[provider] ? provider : 'custom'; document.getElementById('mailHost').value = cfg.smtp_host || ''; document.getElementById('mailPort').value = cfg.smtp_port ? String(cfg.smtp_port) : ''; document.getElementById('mailEncryption').value = cfg.smtp_encryption || 'auto'; document.getElementById('mailUsername').value = cfg.smtp_username || ''; document.getElementById('mailPassword').value = cfg.smtp_password || ''; document.getElementById('mailFromName').value = cfg.from_name || 'MaClaw Hub'; document.getElementById('mailFromEmail').value = cfg.from_email || cfg.smtp_username || ''; }
    function applyMailPreset() { const provider = document.getElementById('mailProvider').value; const preset = findMailPreset(provider); if (provider !== 'custom') { document.getElementById('mailHost').value = preset.smtp_host || ''; document.getElementById('mailPort').value = preset.smtp_port ? String(preset.smtp_port) : ''; document.getElementById('mailEncryption').value = preset.smtp_encryption || 'auto'; if (!document.getElementById('mailFromEmail').value.trim()) document.getElementById('mailFromEmail').value = document.getElementById('mailUsername').value.trim(); } }
    function collectMailConfig() { const host = document.getElementById('mailHost').value.trim(); const username = document.getElementById('mailUsername').value.trim(); const password = document.getElementById('mailPassword').value; const fromEmail = document.getElementById('mailFromEmail').value.trim(); const provider = document.getElementById('mailProvider').value || 'custom'; if (!host || !username || !password || !fromEmail) throw new Error('Please complete the SMTP host, account, password, and sender email first.'); const parsedPort = Number(document.getElementById('mailPort').value || 0); return { enabled: true, provider, smtp_host: host, smtp_port: parsedPort > 0 ? parsedPort : findMailPreset(provider).smtp_port || 587, smtp_encryption: document.getElementById('mailEncryption').value || 'auto', smtp_username: username, smtp_password: password, from_name: document.getElementById('mailFromName').value.trim() || 'MaClaw Hub', from_email: fromEmail }; }
    async function loadMailConfig() { try { const data = await api('/api/admin/mail/config'); renderMailConfig(data || {}); } catch (err) { const msg = tr('mailConfigLoadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function saveMailConfig() { try { const payload = collectMailConfig(); const data = await api('/api/admin/mail/config', { method: 'POST', body: JSON.stringify(payload) }); renderMailConfig(data || payload); const msg = tr('mailConfigSaved'); setOutput(msg); showToast(msg, 'success'); return data || payload; } catch (err) { const msg = tr('mailConfigSaveFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); throw err; } }
    function renderMachineList(items) { machineItemsCache = Array.isArray(items) ? items : []; document.getElementById('machineCountHero').textContent = String(machineItemsCache.length); const root = document.getElementById('machines'); const pager = document.getElementById('machinesPager'); const pagerMeta = document.getElementById('machinesPagerMeta'); const prevButton = document.getElementById('machinesPrevButton'); const nextButton = document.getElementById('machinesNextButton'); const header = `<div class="row header"><div>${tr('machine')}</div><div>${ml('boundEmail')}</div><div>${ml('runtime')}</div><div>${ml('heartbeat')}</div><div>${tr('status')}</div><div>${tr('lastSeen')}</div><div>${ml('actions')}</div></div>`; if (!machineItemsCache.length) { pager.classList.add('hidden'); root.innerHTML = header + '<div class="hint">' + tr('noMachinesLoaded') + '</div>'; return; } const totalPages = Math.max(1, Math.ceil(machineItemsCache.length / machinePageSize)); if (machinePage > totalPages) machinePage = totalPages; if (machinePage < 1) machinePage = 1; const startIndex = (machinePage - 1) * machinePageSize; const pageItems = machineItemsCache.slice(startIndex, startIndex + machinePageSize); root.innerHTML = header + pageItems.map(v => { const state = v.status === 'online' ? tr('online') : v.status === 'offline' ? tr('offline') : (v.status || tr('unknown')); const email = v.user_email || tr('na'); const runtime = [`${formatPlatformLabel(v.platform)}`, v.hostname ? `${ml('host')}: ${v.hostname}` : '', v.arch ? `${ml('arch')}: ${v.arch}` : '', v.app_version ? `${ml('version')}: ${v.app_version}` : ''].filter(Boolean); const heartbeat = [v.heartbeat_interval_sec ? `${ml('interval')}: ${v.heartbeat_interval_sec}s` : '', typeof v.active_sessions === 'number' ? `${ml('activeSessions')}: ${v.active_sessions}` : ''].filter(Boolean); const isOnline = v.online || v.status === 'online'; const displayName = v.alias || v.name || v.machine_id || tr('machine'); const aliasLine = v.alias ? `<div class="item-meta">${v.name || ''}</div>` : ''; const renameBtn = `<button class="btn-secondary" style="height:32px;font-size:12px;padding:0 10px" onclick="renameMachine('${v.machine_id}','${(v.alias || '').replace(/'/g, "\\'")}')">${ml('renameMachine')}</button>`; const deleteBtn = `<button class="btn-danger" style="height:32px;font-size:12px;padding:0 10px" onclick="deleteMachine('${v.machine_id}')">${ml('deleteMachine')}</button>`; const sessionsBtn = isOnline ? `<button class="btn-secondary" style="height:32px;font-size:12px;padding:0 10px" onclick="viewMachineSessions('${v.machine_id}','${v.user_id || ''}','${(displayName).replace(/'/g, "\\'")}')">${ml('viewSessions')}</button>` : ''; return `<div class="row"><div><strong>${displayName}</strong>${aliasLine}<div class="item-meta mono">${v.machine_id || ''}</div></div><div><div>${email}</div><div class="item-meta mono">${v.user_id || ''}</div></div><div>${runtime.map(line => `<div class="item-meta">${line}</div>`).join('')}</div><div>${heartbeat.length ? heartbeat.map(line => `<div class="item-meta">${line}</div>`).join('') : `<div class="item-meta">${tr('na')}</div>`}</div><div><span class="badge ${(isOnline ? 'ok' : 'warn')}">${state}</span></div><div>${v.last_seen_at || tr('na')}</div><div style="display:flex;gap:4px;flex-wrap:wrap">${renameBtn}${sessionsBtn}${deleteBtn}</div></div>`; }).join(''); const start = startIndex + 1; const end = startIndex + pageItems.length; pagerMeta.textContent = totalPages > 1 ? ml('pageSummary').replace('{start}', String(start)).replace('{end}', String(end)).replace('{total}', String(machineItemsCache.length)) : ml('pageSingle').replace('{total}', String(machineItemsCache.length)); prevButton.disabled = machinePage <= 1; nextButton.disabled = machinePage >= totalPages; pager.classList.toggle('hidden', machineItemsCache.length <= machinePageSize); }
    function changeMachinesPage(step) { const totalPages = Math.max(1, Math.ceil(machineItemsCache.length / machinePageSize)); machinePage = Math.min(totalPages, Math.max(1, machinePage + step)); renderMachineList(machineItemsCache); }
    function closeSessionModal() { document.getElementById('sessionModalOverlay').classList.remove('show'); }
    async function viewMachineSessions(machineId, userId, machineName) { const overlay = document.getElementById('sessionModalOverlay'); const title = document.getElementById('sessionModalTitle'); const content = document.getElementById('sessionModalContent'); title.textContent = ml('viewSessionsTitle') + ' \u2014 ' + machineName; content.innerHTML = '<div class="hint">' + tr('checking') + '</div>'; overlay.classList.add('show'); try { const data = await api(`/api/admin/debug/sessions?machine_id=${encodeURIComponent(machineId)}&user_id=${encodeURIComponent(userId)}`); const allSessions = data.sessions || []; const terminalSet = new Set(['exited','stopped','finished','failed','killed','closed','done','error','completed','terminated']); const sessions = allSessions.filter(s => { const st = String((s.Summary || {}).status || '').toLowerCase(); return !terminalSet.has(st); }); if (!sessions.length) { content.innerHTML = '<div class="hint">' + ml('noSessions') + '</div>'; return; } content.innerHTML = sessions.map(s => { const sum = s.Summary || {}; const updatedAt = sum.updated_at ? new Date(sum.updated_at * 1000).toLocaleString() : tr('na'); return `<div class="session-item"><div class="session-field"><span class="session-label">${ml('sessionTitle')}</span><span class="session-value">${sum.title || tr('na')}</span></div><div class="session-field"><span class="session-label">${ml('sessionTask')}</span><span class="session-value">${sum.current_task || tr('na')}</span></div><div class="session-field"><span class="session-label">${ml('sessionTool')}</span><span class="session-value">${sum.tool || tr('na')}</span></div><div class="session-field"><span class="session-label">${ml('sessionStatus')}</span><span class="session-value"><span class="badge ${sum.status === 'running' ? 'ok' : 'info'}">${sum.status || tr('unknown')}</span></span></div><div class="session-field"><span class="session-label">${ml('sessionLastHeartbeat')}</span><span class="session-value">${updatedAt}</span></div></div>`; }).join(''); } catch (err) { content.innerHTML = '<div class="hint" style="color:var(--danger)">' + ml('sessionsLoadFailed').replace('{error}', err.message) + '</div>'; } }
    async function lookupScopedUser(email) { if (!email) return null; const data = await api(`/api/admin/users/lookup?email=${encodeURIComponent(email)}`); return data.user || null; }
    async function setupAdmin() { try { if (adminInitialized) { setSetupAvailability(false); showAuthStage('login'); document.getElementById('loginPassword').focus(); return; } const username = document.getElementById('setupUsername').value.trim(); const data = await api('/api/admin/setup', { method: 'POST', body: JSON.stringify({ username, password: document.getElementById('setupPassword').value }) }); document.getElementById('loginUsername').value = username; document.getElementById('loginPassword').value = ''; adminInitialized = true; setSetupAvailability(false); setOutput(tr('setupDone', { message: data.message || tr('administrator') }), 'loginOutput'); showAuthStage('login'); document.getElementById('loginPassword').focus(); } catch (err) { setOutput(tr('setupFailed', { error: err.message }), 'loginOutput'); } }
