    async function deleteAllMachinesByEmail() { const email = document.getElementById('machineEmailSearch').value.trim(); if (!email) { const msg = ml('emailRequired'); setOutput(msg); showToast(msg, 'error'); return; } if (!confirm(ml('emailDeleteAllConfirm'))) return; try { const data = await api(`/api/admin/machines/by-email?email=${encodeURIComponent(email)}`, { method: 'DELETE' }); const msg = ml('emailDeleteAllSuccess').replace('{count}', String(data.deleted || 0)); setOutput(msg); showToast(msg, 'success'); await loadMachines(); } catch (err) { const msg = ml('emailDeleteAllFailed').replace('{error}', err.message); setOutput(msg); showToast(msg, 'error'); } }
