    async function refreshAll() { await Promise.all([loadCenterStatus(), loadBlockedEmails(), loadBoundUsers(), loadMailConfig(), loadFeishuConfig(), loadMachines(), loadPwaEnrollments()]); }
    applyI18n(); if (token()) { setAuthState(true); restoreTab(); refreshAll(); } else { setAuthState(false); refreshAuthStage(); }
  
